/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — MobileSignalsPage
   Touch-first signal feed for iOS/Capacitor.
   - Signal cards with swipe gestures (swipe left for actions)
   - Tier badges: ULTRA (gold), HIGH CONVICTION (blue), STANDARD (gray)
   - Strategy name + confidence per signal
   - Pull-to-refresh
   - Filter chips: All | Long | Short | Ultra | High Conviction
   Wired: /api/signals, /api/realtime/signals, /api/scanners/signals/live
   SSE fallback to polling. Tap for detail bottom sheet.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useTheme } from '../contexts/ThemeContext';
import { api } from '../utils/api';
import { getApiBase } from '../utils/platform';
import MobileTabBar from '../components/MobileTabBar';

// ── Constants ──────────────────────────────────────────────────────────────
const FONT = "system-ui, -apple-system, 'Helvetica Neue', sans-serif";
const MONO = "'SF Mono', 'JetBrains Mono', 'Menlo', monospace";
const POLL_INTERVAL = 10_000;
const PULL_THRESHOLD = 80;
const SWIPE_THRESHOLD = 60;
const FILTERS = ['All', 'Long', 'Short', 'Ultra', 'High Conviction'];

// ── Tier definitions ──────────────────────────────────────────────────────
const TIER_CONFIG = {
  ultra:           { label: 'ULTRA',           bg: 'rgba(255,215,0,0.15)',   color: '#FFD700', border: 'rgba(255,215,0,0.3)' },
  high_conviction: { label: 'HIGH CONVICTION', bg: 'rgba(88,166,255,0.12)',  color: '#58A6FF', border: 'rgba(88,166,255,0.25)' },
  standard:        { label: 'STANDARD',        bg: 'rgba(139,148,158,0.10)', color: '#8B949E', border: 'rgba(139,148,158,0.20)' },
};

function getTier(conf) {
  if (conf >= 0.85) return TIER_CONFIG.ultra;
  if (conf >= 0.70) return TIER_CONFIG.high_conviction;
  return TIER_CONFIG.standard;
}

function getTierKey(conf) {
  if (conf >= 0.85) return 'ultra';
  if (conf >= 0.70) return 'high_conviction';
  return 'standard';
}

// ── Helpers ────────────────────────────────────────────────────────────────
function confidenceColor(c) {
  if (c >= 0.85) return '#FFD700';
  if (c >= 0.70) return '#3FB950';
  if (c >= 0.50) return '#D29922';
  return '#8B949E';
}

function timeAgo(ts) {
  if (!ts) return '';
  const sec = (Date.now() / 1000) - (typeof ts === 'number' ? ts : new Date(ts).getTime() / 1000);
  if (sec < 0) return 'just now';
  if (sec < 60) return `${Math.floor(sec)}s ago`;
  if (sec < 3600) return `${Math.floor(sec / 60)}m ago`;
  if (sec < 86400) return `${Math.floor(sec / 3600)}h ago`;
  return `${Math.floor(sec / 86400)}d ago`;
}

// ── Regime support ─────────────────────────────────────────────────────────
const REGIME_SUPPORT = {
  trending_up: { long: true, short: false },
  trending_down: { long: false, short: true },
  mean_reverting: { long: true, short: true },
  high_vol: { long: false, short: false },
  normal: { long: true, short: true },
};

function regimeSupportsDirection(regime, direction) {
  const dir = (direction || '').toLowerCase();
  const isBuy = dir === 'long' || dir === 'buy';
  const support = REGIME_SUPPORT[regime] || REGIME_SUPPORT.normal;
  return isBuy ? support.long : support.short;
}

// ── Stat box for modal ────────────────────────────────────────────────────
function StatBox({ label, value, valueColor, bg, textSecondary }) {
  return (
    <div style={{ padding: 12, borderRadius: 10, background: bg }}>
      <div style={{
        fontSize: 10, fontWeight: 600, color: textSecondary,
        textTransform: 'uppercase', letterSpacing: '0.04em', marginBottom: 4,
      }}>
        {label}
      </div>
      <div style={{ fontSize: 16, fontWeight: 700, color: valueColor, fontFamily: MONO }}>
        {value}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
export default function MobileSignalsPage() {
  const navigate = useNavigate();
  const { colors } = useTheme();
  const [signals, setSignals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('All');
  const [selectedSignal, setSelectedSignal] = useState(null);
  const [sseConnected, setSseConnected] = useState(false);
  const [signalBadge, setSignalBadge] = useState(0);
  const sseRef = useRef(null);
  const pollRef = useRef(null);

  // Pull-to-refresh state
  const scrollRef = useRef(null);
  const touchStartY = useRef(0);
  const [pullDistance, setPullDistance] = useState(0);
  const [refreshing, setRefreshing] = useState(false);

  // Swipe state per card
  const [swipedIdx, setSwipedIdx] = useState(null);
  const swipeStartX = useRef(0);
  const [swipeOffset, setSwipeOffset] = useState(0);

  // ── Theme colors ───────────────────────────────────────────────────────
  const bg = colors?.bg || '#0B0F14';
  const surface = colors?.surface || '#161B22';
  const border = colors?.border || 'rgba(255,255,255,0.06)';
  const textPrimary = colors?.textPrimary || '#E6EDF3';
  const textSecondary = colors?.textSecondary || '#8B949E';
  const green = colors?.green || '#3FB950';
  const red = colors?.red || '#F85149';
  const blue = colors?.blue || '#58A6FF';

  // ── Fetch signals ──────────────────────────────────────────────────────
  const fetchSignals = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true);
    try {
      // Try multiple endpoints for best data
      const [realtime, scanner, fallback] = await Promise.allSettled([
        api('/realtime/signals', { silent: true }),
        api('/scanners/signals/live', { silent: true }),
        api('/signals', { silent: true }),
      ]);

      let sigs = [];

      // Prefer realtime data
      if (realtime.status === 'fulfilled' && realtime.value) {
        const d = realtime.value;
        sigs = Array.isArray(d) ? d : (d.signals || []);
      }

      // Merge scanner signals if they have unique entries
      if (scanner.status === 'fulfilled' && scanner.value) {
        const scannerSigs = Array.isArray(scanner.value) ? scanner.value : (scanner.value?.signals || []);
        const existingSymbols = new Set(sigs.map(s => `${s.symbol || s.ticker}-${s.strategy || s.strategy_name}`));
        scannerSigs.forEach(s => {
          const key = `${s.symbol || s.ticker}-${s.strategy || s.strategy_name}`;
          if (!existingSymbols.has(key)) {
            sigs.push(s);
            existingSymbols.add(key);
          }
        });
      }

      // Fallback if nothing from realtime/scanner
      if (sigs.length === 0 && fallback.status === 'fulfilled' && fallback.value) {
        const d = fallback.value;
        sigs = Array.isArray(d) ? d : (d.signals || []);
      }

      setSignals(sigs);
      setSignalBadge(sigs.length);
      setLoading(false);
    } catch {
      setLoading(false);
    } finally {
      setRefreshing(false);
    }
  }, []);

  // ── SSE connection ─────────────────────────────────────────────────────
  useEffect(() => {
    const apiBase = getApiBase();
    let es;
    try {
      es = new EventSource(`${apiBase}/realtime/stream`);
      sseRef.current = es;

      es.onopen = () => setSseConnected(true);

      es.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data);
          if (data.type === 'signals' && Array.isArray(data.signals)) {
            setSignals(data.signals);
            setSignalBadge(data.signals.length);
            setLoading(false);
          } else if (data.symbol || data.ticker) {
            setSignals(prev => {
              const existing = prev.findIndex(s =>
                (s.symbol || s.ticker) === (data.symbol || data.ticker) &&
                s.strategy === data.strategy
              );
              if (existing >= 0) {
                const updated = [...prev];
                updated[existing] = data;
                return updated;
              }
              return [data, ...prev].slice(0, 50);
            });
            setSignalBadge(prev => prev + 1);
            setLoading(false);
          }
        } catch { /* ignore parse errors */ }
      };

      es.onerror = () => {
        setSseConnected(false);
        if (!pollRef.current) {
          fetchSignals();
          pollRef.current = setInterval(fetchSignals, POLL_INTERVAL);
        }
      };
    } catch {
      setSseConnected(false);
    }

    fetchSignals();

    const fallbackTimer = setTimeout(() => {
      if (!sseConnected) {
        pollRef.current = setInterval(fetchSignals, POLL_INTERVAL);
      }
    }, 3000);

    return () => {
      clearTimeout(fallbackTimer);
      if (sseRef.current) { sseRef.current.close(); sseRef.current = null; }
      if (pollRef.current) { clearInterval(pollRef.current); pollRef.current = null; }
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Pull-to-refresh ────────────────────────────────────────────────────
  const onTouchStart = useCallback((e) => {
    if (scrollRef.current?.scrollTop === 0) {
      touchStartY.current = e.touches[0].clientY;
    }
  }, []);

  const onTouchMove = useCallback((e) => {
    if (scrollRef.current?.scrollTop > 0) return;
    const diff = e.touches[0].clientY - touchStartY.current;
    if (diff > 0) setPullDistance(Math.min(diff * 0.5, 120));
  }, []);

  const onTouchEnd = useCallback(() => {
    if (pullDistance >= PULL_THRESHOLD) fetchSignals(true);
    setPullDistance(0);
  }, [pullDistance, fetchSignals]);

  // ── Card swipe handlers ────────────────────────────────────────────────
  const onCardSwipeStart = useCallback((e, idx) => {
    swipeStartX.current = e.touches[0].clientX;
    setSwipedIdx(idx);
    setSwipeOffset(0);
  }, []);

  const onCardSwipeMove = useCallback((e) => {
    if (swipedIdx == null) return;
    const diff = swipeStartX.current - e.touches[0].clientX;
    setSwipeOffset(Math.max(0, Math.min(diff, 120)));
  }, [swipedIdx]);

  const onCardSwipeEnd = useCallback(() => {
    if (swipeOffset < SWIPE_THRESHOLD) {
      setSwipeOffset(0);
      setSwipedIdx(null);
    }
    // Leave open if swiped past threshold
  }, [swipeOffset]);

  const resetSwipe = useCallback(() => {
    setSwipeOffset(0);
    setSwipedIdx(null);
  }, []);

  // ── Filter signals ─────────────────────────────────────────────────────
  const filtered = signals.filter(sig => {
    if (filter === 'All') return true;
    const dir = (sig.direction || sig.side || '').toLowerCase();
    const conf = sig.confidence || sig.confidence_score || 0;
    if (filter === 'Long') return dir === 'long' || dir === 'buy';
    if (filter === 'Short') return dir === 'short' || dir === 'sell';
    if (filter === 'Ultra') return conf >= 0.85;
    if (filter === 'High Conviction') return conf >= 0.70;
    return true;
  });

  // ── Signal Detail Modal (bottom sheet) ─────────────────────────────────
  function SignalModal({ signal, onClose }) {
    if (!signal) return null;
    const dir = (signal.direction || signal.side || '').toLowerCase();
    const isBuy = dir === 'long' || dir === 'buy';
    const conf = signal.confidence || signal.confidence_score || 0;
    const quality = signal.quality_score || signal.quality || null;
    const regime = signal.regime || signal.market_regime || 'normal';
    const regimeSupports = regimeSupportsDirection(regime, dir);
    const dirColor = isBuy ? green : red;
    const tier = getTier(conf);
    const symbol = signal.symbol || signal.ticker;

    return (
      <>
        {/* Backdrop */}
        <div
          onClick={onClose}
          style={{
            position: 'fixed', inset: 0, zIndex: 10000,
            background: 'rgba(0,0,0,0.6)',
            backdropFilter: 'blur(4px)',
            WebkitBackdropFilter: 'blur(4px)',
          }}
        />
        {/* Sheet */}
        <div style={{
          position: 'fixed', bottom: 0, left: 0, right: 0, zIndex: 10001,
          background: surface,
          borderRadius: '20px 20px 0 0',
          padding: '20px 20px calc(env(safe-area-inset-bottom, 20px) + 20px)',
          maxHeight: '85vh', overflowY: 'auto',
          animation: 'slideUp 250ms ease-out',
          WebkitOverflowScrolling: 'touch',
        }}>
          {/* Drag handle */}
          <div style={{
            width: 36, height: 4, borderRadius: 2,
            background: textSecondary, margin: '0 auto 16px', opacity: 0.4,
          }} />

          {/* Header row */}
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 20 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
              <div style={{
                width: 48, height: 48, borderRadius: 12,
                background: `${dirColor}14`,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 24, fontWeight: 700, color: dirColor,
              }}>
                {isBuy ? '\u2191' : '\u2193'}
              </div>
              <div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                  <span style={{ fontSize: 22, fontWeight: 700, color: textPrimary, fontFamily: MONO }}>
                    {symbol}
                  </span>
                  <span style={{
                    fontSize: 10, fontWeight: 700,
                    padding: '2px 8px', borderRadius: 6,
                    background: tier.bg, color: tier.color,
                    border: `1px solid ${tier.border}`,
                    letterSpacing: '0.04em',
                  }}>
                    {tier.label}
                  </span>
                </div>
                <div style={{ fontSize: 13, color: textSecondary, marginTop: 2 }}>
                  {signal.strategy || signal.strategy_name}
                </div>
              </div>
            </div>
            <button
              onClick={onClose}
              aria-label="Close"
              style={{
                width: 44, height: 44, borderRadius: 12,
                background: border, border: 'none', color: textSecondary,
                fontSize: 20, cursor: 'pointer', display: 'flex',
                alignItems: 'center', justifyContent: 'center',
                WebkitTapHighlightColor: 'transparent',
              }}
            >
              &times;
            </button>
          </div>

          {/* Core stats */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 20 }}>
            <StatBox
              label="Direction"
              value={isBuy ? 'LONG' : 'SHORT'}
              valueColor={dirColor}
              bg={border} textSecondary={textSecondary}
            />
            <StatBox
              label="Confidence"
              value={`${Math.round(conf * 100)}%`}
              valueColor={confidenceColor(conf)}
              bg={border} textSecondary={textSecondary}
            />
            {quality != null && (
              <StatBox
                label="Quality Score"
                value={typeof quality === 'number' ? quality.toFixed(2) : quality}
                valueColor={blue}
                bg={border} textSecondary={textSecondary}
              />
            )}
            <StatBox
              label="Time"
              value={timeAgo(signal.generated_at || signal.timestamp || signal.created_at)}
              valueColor={textPrimary}
              bg={border} textSecondary={textSecondary}
            />
          </div>

          {/* Backtest performance */}
          {(signal.backtest_win_rate != null || signal.win_rate != null || signal.profit_factor != null) && (
            <div style={{ marginBottom: 20 }}>
              <div style={{
                fontSize: 11, fontWeight: 700, color: textSecondary,
                textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 10,
              }}>
                Backtest Performance
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
                {(signal.backtest_win_rate ?? signal.win_rate) != null && (
                  <StatBox
                    label="Win Rate"
                    value={`${((signal.backtest_win_rate ?? signal.win_rate) * 100).toFixed(0)}%`}
                    valueColor={(signal.backtest_win_rate ?? signal.win_rate) >= 0.5 ? green : red}
                    bg={border} textSecondary={textSecondary}
                  />
                )}
                {signal.profit_factor != null && (
                  <StatBox
                    label="Profit Factor"
                    value={signal.profit_factor.toFixed(2)}
                    valueColor={signal.profit_factor >= 1.5 ? green : signal.profit_factor >= 1 ? textPrimary : red}
                    bg={border} textSecondary={textSecondary}
                  />
                )}
                {signal.avg_return != null && (
                  <StatBox
                    label="Avg Return"
                    value={`${(signal.avg_return * 100).toFixed(1)}%`}
                    valueColor={signal.avg_return >= 0 ? green : red}
                    bg={border} textSecondary={textSecondary}
                  />
                )}
                {signal.total_trades != null && (
                  <StatBox
                    label="Sample Size"
                    value={signal.total_trades}
                    valueColor={textPrimary}
                    bg={border} textSecondary={textSecondary}
                  />
                )}
              </div>
            </div>
          )}

          {/* Regime context */}
          <div style={{
            padding: 14, borderRadius: 12, background: border, marginBottom: 16,
          }}>
            <div style={{
              fontSize: 11, fontWeight: 700, color: textSecondary, marginBottom: 8,
              textTransform: 'uppercase', letterSpacing: '0.05em',
            }}>
              Regime Context
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <span style={{
                padding: '5px 14px', borderRadius: 16,
                fontSize: 12, fontWeight: 700,
                background: regimeSupports ? `${green}18` : `${red}18`,
                color: regimeSupports ? green : red,
              }}>
                {regimeSupports ? 'Supported' : 'Headwind'}
              </span>
              <span style={{ fontSize: 12, color: textSecondary }}>
                Regime: <span style={{ color: textPrimary, textTransform: 'capitalize' }}>{regime.replace(/_/g, ' ')}</span>
              </span>
            </div>
          </div>

          {/* Chart action button */}
          <div
            onClick={() => { onClose(); navigate(`/charts?symbol=${symbol}`); }}
            style={{
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              padding: '14px 0', borderRadius: 12,
              background: `${blue}18`, border: `1px solid ${blue}30`,
              color: blue, fontSize: 15, fontWeight: 700,
              cursor: 'pointer', WebkitTapHighlightColor: 'transparent',
              marginBottom: 12,
              minHeight: 48,
            }}
          >
            View Chart
          </div>

          {/* Attribution */}
          <div style={{
            fontSize: 12, color: textSecondary, textAlign: 'center',
            paddingTop: 8, borderTop: `1px solid ${border}`,
          }}>
            Signal by <span style={{ color: textPrimary, fontWeight: 600 }}>
              {signal.strategy || signal.strategy_name || 'Aura Alpha'}
            </span>
          </div>
        </div>
      </>
    );
  }

  return (
    <div style={{ background: bg, minHeight: '100vh', fontFamily: FONT, paddingBottom: 90 }}>
      {/* Pull-to-refresh indicator */}
      {pullDistance > 0 && (
        <div style={{
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          height: pullDistance, overflow: 'hidden', transition: 'height 200ms ease',
        }}>
          <div style={{
            width: 28, height: 28, borderRadius: 14,
            border: `2px solid ${pullDistance >= PULL_THRESHOLD ? green : textSecondary}`,
            borderTopColor: 'transparent',
            animation: pullDistance >= PULL_THRESHOLD ? 'spin 0.6s linear infinite' : 'none',
          }} />
        </div>
      )}

      {/* Refreshing spinner */}
      {refreshing && (
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '8px 0' }}>
          <div style={{
            width: 20, height: 20, borderRadius: 10,
            border: `2px solid ${green}`, borderTopColor: 'transparent',
            animation: 'spin 0.6s linear infinite',
          }} />
          <span style={{ marginLeft: 8, fontSize: 12, color: textSecondary }}>Refreshing...</span>
        </div>
      )}

      <div
        ref={scrollRef}
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
        style={{
          padding: '16px 16px 0',
          paddingTop: 'calc(env(safe-area-inset-top, 0px) + 16px)',
          overflowY: 'auto',
          WebkitOverflowScrolling: 'touch',
        }}
      >
        {/* ── Header ──────────────────────────────────────────────────── */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
          <div>
            <div style={{ fontSize: 24, fontWeight: 700, color: textPrimary }}>Signals</div>
            <div style={{ fontSize: 12, color: textSecondary, marginTop: 2 }}>
              {sseConnected ? (
                <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
                  <span style={{
                    width: 6, height: 6, borderRadius: 3, background: green,
                    display: 'inline-block', animation: 'pulse 2s ease-in-out infinite',
                  }} />
                  Live streaming
                </span>
              ) : (
                <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
                  <span style={{ width: 6, height: 6, borderRadius: 3, background: '#D29922', display: 'inline-block' }} />
                  Polling every 10s
                </span>
              )}
            </div>
          </div>
          <div style={{
            fontSize: 12, fontWeight: 600, color: textSecondary,
            padding: '4px 10px', borderRadius: 8, background: border,
          }}>
            {signals.length} signal{signals.length !== 1 ? 's' : ''}
          </div>
        </div>

        {/* ── Filter Chips ────────────────────────────────────────────── */}
        <div style={{
          display: 'flex', gap: 8, marginBottom: 16,
          overflowX: 'auto', paddingBottom: 4,
          WebkitOverflowScrolling: 'touch',
          scrollbarWidth: 'none',
        }}>
          {FILTERS.map(f => {
            const isActive = filter === f;
            // Tier-based coloring for filter chips
            let chipColor = green;
            if (f === 'Ultra') chipColor = '#FFD700';
            else if (f === 'High Conviction') chipColor = blue;
            else if (f === 'Short') chipColor = red;

            return (
              <button
                key={f}
                onClick={() => setFilter(f)}
                style={{
                  padding: '8px 16px', borderRadius: 20,
                  fontSize: 13, fontWeight: 600,
                  whiteSpace: 'nowrap',
                  border: isActive ? `1.5px solid ${chipColor}` : `1px solid ${border}`,
                  background: isActive ? `${chipColor}14` : 'transparent',
                  color: isActive ? chipColor : textSecondary,
                  cursor: 'pointer',
                  WebkitTapHighlightColor: 'transparent',
                  transition: 'all 200ms ease',
                  flexShrink: 0,
                  minHeight: 36,
                }}
              >
                {f}
              </button>
            );
          })}
        </div>

        {/* ── Signal Cards ────────────────────────────────────────────── */}
        {loading ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {[1,2,3,4].map(n => (
              <div key={n} style={{
                height: 88, borderRadius: 14,
                background: `linear-gradient(90deg, ${surface} 0%, rgba(255,255,255,0.03) 50%, ${surface} 100%)`,
                backgroundSize: '200% 100%',
                animation: 'shimmer 1.5s ease-in-out infinite',
              }} />
            ))}
          </div>
        ) : filtered.length > 0 ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            {filtered.map((sig, i) => {
              const dir = (sig.direction || sig.side || '').toLowerCase();
              const isBuy = dir === 'long' || dir === 'buy';
              const conf = sig.confidence || sig.confidence_score || 0;
              const quality = sig.quality_score || sig.quality || null;
              const dirColor = isBuy ? green : red;
              const symbol = sig.symbol || sig.ticker || '???';
              const strategy = sig.strategy || sig.strategy_name || 'Signal';
              const ts = sig.generated_at || sig.timestamp || sig.created_at;
              const tier = getTier(conf);
              const isThisSwiped = swipedIdx === i;
              const cardOffset = isThisSwiped ? swipeOffset : 0;

              return (
                <div key={`${symbol}-${strategy}-${i}`} style={{
                  position: 'relative', overflow: 'hidden', borderRadius: 14,
                }}>
                  {/* Swipe action buttons */}
                  <div style={{
                    position: 'absolute', top: 0, right: 0, bottom: 0,
                    display: 'flex', alignItems: 'stretch',
                    opacity: isThisSwiped && swipeOffset > 30 ? 1 : 0,
                    transition: 'opacity 150ms ease',
                  }}>
                    <div
                      onClick={() => { resetSwipe(); setSelectedSignal(sig); }}
                      style={{
                        width: 60, display: 'flex', flexDirection: 'column',
                        alignItems: 'center', justifyContent: 'center',
                        background: blue, color: '#fff', fontSize: 10, fontWeight: 700,
                        cursor: 'pointer', gap: 2,
                      }}
                    >
                      <span style={{ fontSize: 16 }}>i</span>
                      Detail
                    </div>
                    <div
                      onClick={() => { resetSwipe(); navigate(`/charts?symbol=${symbol}`); }}
                      style={{
                        width: 60, display: 'flex', flexDirection: 'column',
                        alignItems: 'center', justifyContent: 'center',
                        background: green, color: '#fff', fontSize: 10, fontWeight: 700,
                        cursor: 'pointer', gap: 2,
                      }}
                    >
                      <span style={{ fontSize: 16 }}>{'\u2197'}</span>
                      Chart
                    </div>
                  </div>

                  {/* Card */}
                  <div
                    onTouchStart={(e) => onCardSwipeStart(e, i)}
                    onTouchMove={onCardSwipeMove}
                    onTouchEnd={onCardSwipeEnd}
                    onClick={() => {
                      if (cardOffset < 10) setSelectedSignal(sig);
                    }}
                    style={{
                      background: surface,
                      borderRadius: 14,
                      border: `1px solid ${border}`,
                      padding: '14px 16px',
                      cursor: 'pointer',
                      WebkitTapHighlightColor: 'transparent',
                      transform: `translateX(-${cardOffset}px)`,
                      transition: isThisSwiped ? 'none' : 'transform 200ms ease',
                      position: 'relative',
                      zIndex: 1,
                    }}
                    role="button"
                    tabIndex={0}
                    aria-label={`${symbol} ${isBuy ? 'buy' : 'sell'} signal, ${Math.round(conf * 100)}% confidence`}
                  >
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                      {/* Left: direction + ticker + strategy */}
                      <div style={{ display: 'flex', alignItems: 'center', gap: 12, flex: 1, minWidth: 0 }}>
                        <div style={{
                          width: 44, height: 44, borderRadius: 12,
                          background: `${dirColor}14`,
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          fontSize: 20, fontWeight: 700, color: dirColor,
                          flexShrink: 0,
                        }}>
                          {isBuy ? '\u2191' : '\u2193'}
                        </div>
                        <div style={{ minWidth: 0 }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap' }}>
                            <span style={{ fontSize: 16, fontWeight: 700, color: textPrimary, fontFamily: MONO }}>
                              {symbol}
                            </span>
                            {/* Tier Badge */}
                            <span style={{
                              fontSize: 9, fontWeight: 700,
                              padding: '2px 7px', borderRadius: 5,
                              background: tier.bg, color: tier.color,
                              border: `1px solid ${tier.border}`,
                              letterSpacing: '0.04em',
                              lineHeight: 1.4,
                            }}>
                              {tier.label}
                            </span>
                          </div>
                          <div style={{
                            fontSize: 11, color: textSecondary, marginTop: 3,
                            overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                          }}>
                            {strategy}
                          </div>
                        </div>
                      </div>

                      {/* Right: confidence + quality + time */}
                      <div style={{ textAlign: 'right', flexShrink: 0, marginLeft: 8 }}>
                        <div style={{
                          fontSize: 18, fontWeight: 700, fontFamily: MONO,
                          color: confidenceColor(conf),
                        }}>
                          {Math.round(conf * 100)}%
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 6, justifyContent: 'flex-end', marginTop: 3 }}>
                          {quality != null && (
                            <span style={{
                              fontSize: 10, fontWeight: 600, color: blue,
                              padding: '1px 6px', borderRadius: 4,
                              background: `${blue}14`,
                            }}>
                              Q{typeof quality === 'number' ? quality.toFixed(1) : quality}
                            </span>
                          )}
                          <span style={{ fontSize: 10, color: textSecondary }}>
                            {timeAgo(ts)}
                          </span>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          /* Empty state */
          <div style={{ textAlign: 'center', padding: '60px 20px', color: textSecondary }}>
            <div style={{
              width: 64, height: 64, borderRadius: 16,
              background: `${blue}10`, margin: '0 auto 16px',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}>
              <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke={blue} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="11" cy="11" r="8" />
                <path d="M21 21l-4.35-4.35" />
              </svg>
            </div>
            <div style={{ fontSize: 16, fontWeight: 600, color: textPrimary, marginBottom: 6 }}>
              {filter !== 'All' ? `No ${filter.toLowerCase()} signals` : 'Scanning 2,728 symbols...'}
            </div>
            <div style={{ fontSize: 13, lineHeight: 1.5 }}>
              {filter !== 'All'
                ? 'Try changing your filter or check back soon.'
                : 'No signals yet. The engine scans continuously and will surface opportunities as they appear.'}
            </div>
          </div>
        )}

        {/* Swipe hint */}
        {filtered.length > 0 && (
          <div style={{
            textAlign: 'center', padding: '16px 0 8px',
            fontSize: 11, color: textSecondary, opacity: 0.6,
          }}>
            Swipe left on a signal for quick actions
          </div>
        )}
      </div>

      {/* Signal Detail Modal */}
      {selectedSignal && (
        <SignalModal signal={selectedSignal} onClose={() => setSelectedSignal(null)} />
      )}

      {/* Tab Bar */}
      <MobileTabBar signalBadgeCount={signalBadge} />

      {/* Inline animations */}
      <style>{`
        @keyframes shimmer {
          0% { background-position: -200% 0; }
          100% { background-position: 200% 0; }
        }
        @keyframes slideUp {
          from { transform: translateY(100%); }
          to { transform: translateY(0); }
        }
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
        div::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
}
